// projectStatusLabel returns a human-readable label for a project status.
func projectStatusLabel(s ProjectStatus) string {
	switch s {
	case StatusGreen:
		return "Stable"
	case StatusYellow:
		return "Active"
	case StatusRed:
		return "Unattended"
	default:
		return "Registered"
	}
}

// platformIcon returns a Unicode icon for the platform type.
func platformIcon(platform string) string {
	switch platform {
	case "go":
		return "⚙"
	case "javascript", "node":
		return "🌐"
	case "cocoa":
		return "📱"
	case "java", "android":
		return "🤖"
	case "python":
		return "🐍"
	case "react-native":
		return "⚛"
	default:
		if platform != "" {
			return "💻"
		}
		return ""
	}
}

